const auth = $input.first().json.headers.authorization || '';
const token = auth.replace(/^Bearer\s+/i, '').trim();

// Format: tg_<user_id>_<ts> or usr_<user_id>_<ts>
const parts = token.split('_');
if (parts.length < 2) {
  return [{ json: { ok: false, error: 'Invalid token format' } }];
}
const userId = parseInt(parts[1]);
if (isNaN(userId)) {
  return [{ json: { ok: false, error: 'Invalid user ID in token' } }];
}

// Verify user exists
const { rows } = await $pg.query('SELECT id, is_admin FROM user_list WHERE id = $1', [userId]);
if (!rows.length) {
  return [{ json: { ok: false, error: 'User not found' } }];
}

return [{ json: { ok: true, user_id: userId, is_admin: rows[0].is_admin } }];

const rows = await $pg.query("SELECT key, value FROM pengaturan WHERE instansi_id = 'bapperida' AND key IN ('face_liveness_enabled', 'face_threshold', 'face_meja_threshold', 'face_liveness_score', 'face_mandatory_nips')");

const settings = {};
for (const r of rows) {
  if (r.key === 'face_liveness_enabled') settings.liveness_enabled = r.value === 'true';
  else if (r.key === 'face_threshold') settings.face_threshold = parseFloat(r.value) || 0.55;
  else if (r.key === 'face_meja_threshold') settings.meja_threshold = parseFloat(r.value) || 0.55;
  else if (r.key === 'face_liveness_score') settings.liveness_score = parseFloat(r.value) || 0.40;
  else if (r.key === 'face_mandatory_nips') {
    try { settings.mandatory_nips = JSON.parse(r.value); } catch { settings.mandatory_nips = []; }
  }
}

return [{ json: { ok: true, settings } }];

const body = $input.first().json.body || $input.first().json;
const auth = (body.headers?.authorization || '').replace(/^Bearer\s+/i, '').trim();
const parts = auth.split('_');
const userId = parseInt(parts[1]);

if (!userId) {
  return [{ json: { ok: false, error: 'Unauthorized' } }];
}

const { rows } = await $pg.query('SELECT id, is_admin FROM user_list WHERE id = $1', [userId]);
if (!rows.length || !rows[0].is_admin) {
  return [{ json: { ok: false, error: 'Admin access required' } }];
}

return [{ json: { ok: true, user_id: userId, settings: body.settings || body } }];

const s = $input.first().json.settings || {};
const updates = [];
const params = [];
let idx = 1;

const fields = [
  ['face_liveness_enabled', s.liveness_enabled],
  ['face_threshold', s.face_threshold],
  ['face_meja_threshold', s.meja_threshold],
  ['face_liveness_score', s.liveness_score],
  ['face_mandatory_nips', Array.isArray(s.mandatory_nips) ? JSON.stringify(s.mandatory_nips) : s.mandatory_nips]
];

for (const [key, val] of fields) {
  if (val !== undefined && val !== null) {
    updates.push(`(${idx}, '${key}', '${String(val)}', 'bapperida')`);
    idx++;
  }
}

if (!updates.length) {
  return [{ json: { ok: false, error: 'No settings to update' } }];
}

const sql = `INSERT INTO pengaturan (id, key, value, instansi_id) VALUES ${updates.join(', ')}
  ON CONFLICT (key, instansi_id) DO UPDATE SET value = EXCLUDED.value`;

await $pg.query(sql);
return [{ json: { ok: true, updated: fields.map(f => f[0]) } }];
